#! /usr/bin/env python3

import rclpy
from rlclpy.node import Node
from std_msgs.msg import Int32
import time

class EvenTalker(Node):

    def __init__(self):
        #Name for node "even_talker"
        super().__init__('even_talker')

        self.publisher = self.create_publisher(Int32, 'my_chat_topic', 10)

        time_period = 0.1
        self.timer = self.create_timer(time_period, self.timer_callback)

        self.get_logger().info("Node even_talker is run")

    #------------------------------------
    # This function runs at every 0.1s
    #------------------------------------
    def timer_cllback(self):
        num = 0
        msg = Int32() # empty message
        msg.data = num
        self.publisher.publish(msg)
        self.get_logger().info(msg.data)


#------------------------------------
# Main function
#------------------------------------
def main():
    rclpy.init()    # begin work with ROS 2

    node = EvenTalker()

    try:
        rclpy.spin(node)
    except:
        pass
    finally:
        node.destroy_node()
        rclpy.shutdown()

if __name__ == '__main__':
    main()

    
